</code></pre> <ul> <li><code>MAXN</code>이 선언되어야 함</li> <li><code>void init(int _N) {}</code> : 초기화</li> <li><code>void solve(ll lambda) {}</code> : 주어진 \(\lambda\)에 대하여 최적의 \(dp2[N]\)을 구함 (<code>dp</code>, <code>cnt</code>, <code>memo</code>, <code>V</code>를 채움)<ul> <li><code>dp[i]</code> : \(dp2[i]\)의 값</li> <li><code>cnt[i]</code> : \(dp2[i]\)까지 사용한 transition의 개수</li> <li><code>memo[i]</code> : \(dp2[i]\)에서 사용한 마지막 transition의 위치</li> <li><code>V</code> : 복구한 최적해</li> <li>\(cost(p, q)\)가 monge해야 함</li> <li>문제 상황에 따라 <code>get_opt(i)</code>, <code>cost(p, q)</code> 부분을 구현하여 사용함</li> <li><code>get_opt(i)</code> : \(dp[j] + cost(j, i) \cdot 2\)를 최적화시키는 \(j&lt;i\)를 구함</li> <li>반정수 범위 이분탐색을 위해 <code>lambda</code>는 홀수, <code>cost(p, q)</code>에 2를 곱하여 계산</li> </ul> </li> <li><code>pair&lt;ll, vector&lt;int&gt;&gt; alien(int K) {}</code> : 주어진 \(K\)에 대해 (최적의 \(dp[N][K]\), 역추적한 최적해)를 리턴함<ul> <li><code>lambda</code>는 그을 접선의 기울기를 의미함</li> <li>역추적한 최적해는 \([a_0=0, a_1, \cdots, a_{K-1}, a_K=N]\)의 형태임</li> </ul> </li> </ul> example<pre><code>void test_alien()
{
    // min, cost(j, i) = (i-j)*(i-j)
    Alien::init(15);
    auto [ans, ansV] = Alien::alien(4);

    assert(ans == 57 &amp;&amp; ansV == vector&lt;int&gt;({0, 3, 7, 11, 15}));
}
</code></pre>

cht.cpp<pre><code>namespace CHT
{
    typedef __int128 dll;
    struct Line { ll a, b; };
    struct Frac
    {
        ll u, d;
        Frac(ll _u, ll _d) : u(_u), d(_d) { if(d&lt;0) u=-u, d=-d; }
        bool operator &lt; (const Frac &amp;ot) const { return (dll)u*ot.d &lt; (dll)ot.u*d; }
        bool operator &gt; (const Frac &amp;ot) const { return (dll)u*ot.d &gt; (dll)ot.u*d; }
    };
    ll divfloor(ll u, ll d) { return u/d - ((u^d)&lt;0 &amp;&amp; u%d); }
    ll divceil(ll u, ll d) { return u/d + ((u^d)&gt;0 &amp;&amp; u%d); }

    // min/max : ?, slope : ?, dir : ?
    struct CHT
    {
        // Get cross point of line p, q
        // If all queries are integer, change 'Frac' to 'div'
        Frac cross(const Line &amp;p, const Line &amp;q) { return Frac(p.b-q.b, q.a-p.a); } // dir + : divfloor, dir - : divceil
        deque&lt;Line&gt; V;

        // Insert line p = ax+b
        // b must be increasing (or decreasing) ('slope')
        // cross(V[i-1], V[i]) &lt; (or &gt;) cross(V[i], V[i+1]) ('dir')
        void push(Line p)
        {
            if(!V.empty() &amp;&amp; V.back().a==p.a)
            {
                if(V.back().b &lt;= p.b) return; // min : &lt;= , max : &gt;=
                V.pop_back();
            }
            while(V.size()&gt;1 &amp;&amp; !(cross(V[V.size()-2], V[V.size()-1]) &lt; cross(V[V.size()-1], p))) V.pop_back(); // dir + : &lt;, dir - : &gt;
            V.push_back(p);
        }

        // Get min (or max) value at x in O(logN)
        ll query(ll x)
        {
            assert(!V.empty());
            int lo=0, hi=V.size();
            while(lo+1&lt;hi)
            {
                int mid=lo+hi&gt;&gt;1;
                if(cross(V[mid-1], V[mid]) &lt; Frac(x, 1)) lo=mid; // dir + : &lt;, dir - : &gt;
                else hi=mid;
            }
            return V[lo].a*x+V[lo].b;
        }

        // Get min (or max) value at x in ammortized O(1)
        // x must be increasing (or decreasing) ('dir')
        ll query2(ll x)
        {
            assert(!V.empty());
            while(V.size()&gt;1 &amp;&amp; cross(V[0], V[1]) &lt; Frac(x, 1)) V.pop_front(); // dir + : &lt;, dir - : &gt;
            return V[0].a*x+V[0].b;
        }
    };
}
</code></pre>

template<pre><code>namespace CHT
{
    typedef __int128 dll;
    struct Line { ll a, b; };
    struct Frac
    {
        ll u, d;
        Frac(ll _u, ll _d) : u(_u), d(_d) { if(d&lt;0) u=-u, d=-d; }
        bool operator &lt; (const Frac &amp;ot) const { return (dll)u*ot.d &lt; (dll)ot.u*d; }
        bool operator &gt; (const Frac &amp;ot) const { return (dll)u*ot.d &gt; (dll)ot.u*d; }
    };
    ll divfloor(ll u, ll d) { return u/d - ((u^d)&lt;0 &amp;&amp; u%d); }
    ll divceil(ll u, ll d) { return u/d + ((u^d)&gt;0 &amp;&amp; u%d); }

    // min/max : ?, slope : ?, dir : ?
    struct CHT
    {
        // Get cross point of line p, q
        // If all queries are integer, change 'Frac' to 'div'
        Frac cross(const Line &amp;p, const Line &amp;q) { return Frac(p.b-q.b, q.a-p.a); } // dir + : divfloor, dir - : divceil
        deque&lt;Line&gt; V;

        // Insert line p = ax+b
        // b must be increasing (or decreasing) ('slope')
        // cross(V[i-1], V[i]) &lt; (or &gt;) cross(V[i], V[i+1]) ('dir')
        void push(Line p) {}

        // Get min (or max) value at x in O(logN)
        ll query(ll x) {}

        // Get min (or max) value at x in ammortized O(1)
        // x must be increasing (or decreasing) ('dir')
        ll query2(ll x) {}
    };
}
</code></pre> <ul> <li>문제 상황에 따라 <code>min/max</code> (최소/최대 쿼리), <code>slope</code> (삽입되는 직선들의 기울기 증가/감소), <code>dir</code> (삽입 직선들의 교점의 x좌표 증가/감소)이 결정된다.</li> <li><code>Frac cross(const Line &amp;p, const Line &amp;q) {}</code> : 두 직선의 교점의 x좌표를 <code>Frac</code> 자료형으로 리턴함<ul> <li>모든 쿼리들이 정수라면, <code>Frac</code> 대신 <code>dir</code>이 증가한다면 <code>divfloor</code>, <code>dir</code>이 감소한다면 <code>divceil</code>으로 대체할 수 있음</li> </ul> </li> <li><code>void push(Line p) {}</code> : 일차함수 \(y=ax+b\)를 추가함<ul> <li>삽입되는 기울기 \(a\)는 <code>slope</code>에 따라 증가하거나 감소해야함</li> <li><code>dir</code>이 증가한다면 <code>cross(V[i-1], V[i]) &lt; cross(V[i], V[i+1])</code>, 감소한다면 <code>cross(V[i-1], V[i]) &gt; cross(V[i], V[i+1])</code>를 만족함</li> </ul> </li> <li><code>ll query(ll x) {}</code> : 특정 \(x\)에서의 함숫값들 중 <code>min/max</code>에 따라 최솟값 혹은 최댓값을 리턴함</li> <li><code>ll query2(ll x) {}</code> : 특정 \(x\)에서의 함숫값들 중 <code>min/max</code>에 따라 최솟값 혹은 최댓값을 리턴함<ul> <li>쿼리로 주어지는 \(x\)는 <code>dir</code>에 따라 증가하거나 감소해야 함</li> </ul> </li> </ul> example<pre><code>void test_cht()
{
    // min/max : min, slope : -, dir : +
    CHT::CHT cht;

    cht.push({0, 1});
    cht.push({-1, -1});
    cht.push({-2, -1});

    assert(cht.query(-2) == 1);
    assert(cht.query(-1) == 0);
    assert(cht.query(0) == -1);
    assert(cht.query(1) == -3);

    assert(cht.query2(-2) == 1);
    assert(cht.query2(-1) == 0);
    assert(cht.query2(0) == -1);
    assert(cht.query2(1) == -3);
}
</code></pre>

monotone_queue.cpp<pre><code>namespace Monotone_Queue
{
    // MAXN must be defined
    const int MAXN = 5e5;
    int N;

    // dp[i] : optimal dp value of i
    // cnt[i] : how much transitions were used in optimal dp[i]
    // memo[i] : previous transition position from i
    // V : restored optimal solution
    ll dp[MAXN+10];
    int cnt[MAXN+10], memo[MAXN+10];
    vector&lt;int&gt; V;

    void init(int _N)
    {
        N=_N;
    }

    // cost(p, q) must be monge
    ll cost(int p, int q) {}

    // Get maximum x that dp[p]+cost(p, x) &lt; dp[q]+cost(q, x) (p is optimal than q)
    // p &lt; q must hold
    int cross(int p, int q)
    {
        int lo=q, hi=N+1;
        while(lo+1&lt;hi)
        {
            int mid=lo+hi&gt;&gt;1;
            if(dp[p]+cost(p, mid) &lt; dp[q]+cost(q, mid)) lo=mid; // min : &lt;, max : &gt;
            else hi=mid;
        }
        return lo;
    }

    // Get optimal dp[N]
    // dp[i] = min(or max)_{j&lt;i} (dp[j] + cost(j, i)) 
    // changes dp, cnt, memo, V
    void solve()
    {
        // initialize dp, cnt, memo, V, (other data structures)
        for(int i=0; i&lt;=N; i++) dp[i]=cnt[i]=memo[i]=0;
        V.clear();

        deque&lt;int&gt; DQ;
        DQ.push_back(0);

        for(int i=1; i&lt;=N; i++)
        {
            while(DQ.size()&gt;1 &amp;&amp; dp[DQ[0]]+cost(DQ[0], i) &gt;= dp[DQ[1]]+cost(DQ[1], i)) DQ.pop_front(); // min : &gt;=, max : &lt;=

            // opt = argmin(or max)_{j&lt;i} (dp[j] + cost(j, i))
            int opt = DQ.front();
            dp[i] = dp[opt]+cost(opt, i);
            cnt[i] = cnt[opt]+1;
            memo[i] = opt;

            // cross(DQ[i-1], DQ[i]) &lt; cross(DQ[i], DQ[i+1])
            while(DQ.size()&gt;1 &amp;&amp; !(cross(DQ[DQ.size()-2], DQ[DQ.size()-1]) &lt; cross(DQ[DQ.size()-1], i))) DQ.pop_back();
            DQ.push_back(i);
        }

        for(int i=N; i&gt;0;)
        {
            V.push_back(i);
            i=memo[i];
        }
        V.push_back(0);
        reverse(V.begin(), V.end());
    }
}
</code></pre>

